!function(){"use strict";window.CollaborationManager=class{constructor(){this.user=null,this.init()}init(){console.log("🤝 Collaboration v6.0"),this.loadUser(),this.injectUI()}loadUser(){let e=localStorage.getItem("claudia_user");if(e)e=JSON.parse(e);else{const t=prompt("👤 Tu nombre:","Usuario")||"Usuario";e={id:Date.now(),name:t,avatar:"👷"},localStorage.setItem("claudia_user",JSON.stringify(e))}this.user=e}injectUI(){const e=document.querySelector(".header");if(!e)return;const t=document.createElement("button");t.className="collab-btn",t.innerHTML="👥 Equipo",t.onclick=()=>this.show(),t.style.cssText="background: linear-gradient(135deg, #10b981, #059669); color: white; border: none; padding: 12px 20px; border-radius: 24px; font-weight: 600; cursor: pointer; box-shadow: 0 4px 12px rgba(16,185,129,0.3);",e.appendChild(t)}show(){const e=document.createElement("div");e.style.cssText="position: fixed; top: 0; right: 0; width: 400px; height: 100vh; background: white; box-shadow: -4px 0 24px rgba(0,0,0,0.2); z-index: 10000; padding: 20px; overflow-y: auto;",e.innerHTML=`\n                <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;">\n                    <h3 style="margin: 0;">👥 Colaboración</h3>\n                    <button onclick="this.parentElement.parentElement.remove()" style="background: #ef4444; color: white; border: none; width: 32px; height: 32px; border-radius: 50%; cursor: pointer;">✕</button>\n                </div>\n\n                <div style="background: #f0fdf4; padding: 15px; border-radius: 8px; border: 2px solid #10b981; margin-bottom: 20px;">\n                    <h4 style="margin: 0 0 10px 0;">📤 Compartir Proyecto</h4>\n                    <input type="text" readonly value="https://claudia.app/share/${Date.now()}" style="width: 100%; padding: 8px; border: 2px solid #10b981; border-radius: 6px; margin-bottom: 10px;">\n                    <button onclick="alert('✅ Link copiado')" style="width: 100%; background: #10b981; color: white; border: none; padding: 10px; border-radius: 6px; font-weight: 600; cursor: pointer;">📋 Copiar Link</button>\n                </div>\n\n                <div style="background: #f5f5f5; padding: 12px; border-radius: 8px; margin-bottom: 10px;">\n                    <div style="font-weight: 600; margin-bottom: 5px;">${this.user.avatar} ${this.user.name}</div>\n                    <div style="color: #f59e0b; font-size: 12px; font-weight: 600;">👑 Propietario</div>\n                </div>\n\n                <h4 style="margin: 20px 0 10px 0;">💬 Comentarios</h4>\n                <div id="comments-area" style="max-height: 300px; overflow-y: auto; margin-bottom: 10px;"></div>\n                <textarea id="comment-input" placeholder="Agregar comentario..." style="width: 100%; padding: 10px; border: 2px solid #e0e0e0; border-radius: 8px; resize: vertical; min-height: 60px; margin-bottom: 10px;"></textarea>\n                <button onclick="window.collaborationManager.addComment()" style="width: 100%; background: #10b981; color: white; border: none; padding: 12px; border-radius: 8px; font-weight: 600; cursor: pointer;">💬 Agregar Comentario</button>\n            `,document.body.appendChild(e),this.loadComments()}addComment(){const e=document.getElementById("comment-input");if(!e||!e.value.trim())return;const t=`claudia_comments_${(document.getElementById("project-name")?.value||"Mi Proyecto").replace(/[^a-zA-Z0-9]/g,"_")}`;let o=JSON.parse(localStorage.getItem(t)||"[]");o.push({user:this.user.name,avatar:this.user.avatar,text:e.value.trim(),time:Date.now()}),localStorage.setItem(t,JSON.stringify(o)),e.value="",this.loadComments()}loadComments(){const e=document.getElementById("comments-area");if(!e)return;const t=`claudia_comments_${(document.getElementById("project-name")?.value||"Mi Proyecto").replace(/[^a-zA-Z0-9]/g,"_")}`,o=JSON.parse(localStorage.getItem(t)||"[]");0!==o.length?e.innerHTML=o.map(e=>`\n                <div style="background: #f5f5f5; padding: 10px; border-radius: 8px; border-left: 3px solid #10b981; margin-bottom: 8px;">\n                    <div style="font-weight: 600; font-size: 13px; margin-bottom: 5px;">${e.avatar} ${e.user}</div>\n                    <div style="font-size: 13px; color: #333;">${e.text}</div>\n                    <div style="font-size: 11px; color: #999; margin-top: 5px;">${this.timeAgo(e.time)}</div>\n                </div>\n            `).join(""):e.innerHTML='<div style="text-align: center; padding: 20px; color: #999;">Sin comentarios</div>'}timeAgo(e){const t=Math.floor((Date.now()-e)/6e4);if(t<1)return"Ahora";if(t<60)return`Hace ${t} min`;const o=Math.floor(t/60);return o<24?`Hace ${o} h`:`Hace ${Math.floor(o/24)} días`}},"loading"===document.readyState?document.addEventListener("DOMContentLoaded",()=>{window.collaborationManager=new CollaborationManager}):window.collaborationManager=new CollaborationManager}();